// Valida e normaliza o corpo da requisição. Captura o tempo inicial para latency_ms.
const body = $json.body || $json;
const question = (body.question || '').toString().trim();
if (!question) {
  throw new Error('Campo obrigatório ausente: "question".');
}
const userRole = (body.user_role || 'cockpit_executive').toString().trim();
let topK = parseInt(body.top_k, 10);
if (!Number.isFinite(topK) || topK < 1 || topK > 20) topK = 6;

return {
  json: {
    question,
    user_role: userRole,
    top_k: topK,
    embed_model: $env.EMBED_MODEL || 'text-embedding-3-small',
    llm_model: $env.LLM_MODEL || 'claude-opus-4-8',
    started_ms: Date.now(),
  },
};

// Extrai o vetor da resposta de embeddings e formata como literal pgvector para a busca.
const resp = $json;
let vector = null;
if (resp && Array.isArray(resp.data) && resp.data[0] && Array.isArray(resp.data[0].embedding)) {
  vector = resp.data[0].embedding;
} else if (Array.isArray(resp.embedding)) {
  vector = resp.embedding;
}
if (!vector || vector.length === 0) {
  throw new Error('Não foi possível obter o embedding da pergunta.');
}

const meta = $('Validar Entrada').item.json;
return {
  json: {
    question: meta.question,
    user_role: meta.user_role,
    top_k: meta.top_k,
    llm_model: meta.llm_model,
    started_ms: meta.started_ms,
    query_vector: '[' + vector.map((x) => Number(x)).join(',') + ']',
  },
};

// Constrói o prompt 'grounded' (ancorado) a partir dos documentos recuperados.
// O modelo só pode responder com base nas fontes; caso contrário, declara não saber.
const meta = $('Preparar Vetor da Consulta').first().json;
const rows = $input.all().map((i) => i.json);

const retrievedDocIds = rows.map((r) => r.doc_id);
const fontes = rows.map((r) => `${r.title} (${r.periodo || 's/ período'})`);

const contexto = rows.length === 0
  ? '(Nenhum documento relevante encontrado na base de conhecimento.)'
  : rows.map((r, idx) =>
      `[FONTE ${idx + 1} | ${r.company_id || 'CONSOLIDADO'} | ${r.periodo || 's/ período'} | similaridade ${Number(r.similaridade).toFixed(3)}]\n${r.content}`
    ).join('\n\n');

const systemPrompt =
  'Você é o assistente analítico do Cockpit Financeiro Estratégico do Grupo Aurora. ' +
  'Responda SEMPRE em português do Brasil, de forma objetiva e executiva. ' +
  'Use EXCLUSIVAMENTE as informações das FONTES fornecidas abaixo. ' +
  'Não invente números nem extrapole além do contexto. ' +
  'Se as fontes não contiverem a resposta, diga claramente que a informação não está disponível na base. ' +
  'Valores monetários estão em BRL (R$). Cite as fontes relevantes ao final.';

const userPrompt =
  `PERGUNTA DO USUÁRIO:\n${meta.question}\n\n` +
  `FONTES RECUPERADAS DA BASE DE CONHECIMENTO:\n${contexto}\n\n` +
  'Com base apenas nas fontes acima, responda à pergunta.';

return [{
  json: {
    question: meta.question,
    user_role: meta.user_role,
    llm_model: meta.llm_model,
    started_ms: meta.started_ms,
    retrieved_doc_ids: retrievedDocIds,
    fontes,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
  },
}];

// Extrai o texto da resposta da API Anthropic e as métricas de tokens/latência.
const meta = $('Montar Prompt Ancorado').item.json;
const resp = $json;

// Resposta Anthropic: { content: [ { type: 'text', text: '...' } ], usage: { input_tokens, output_tokens }, model }
let answer = '';
if (resp && Array.isArray(resp.content)) {
  answer = resp.content
    .filter((b) => b && b.type === 'text' && typeof b.text === 'string')
    .map((b) => b.text)
    .join('\n')
    .trim();
}
if (!answer) {
  answer = 'Não foi possível gerar uma resposta a partir das fontes disponíveis.';
}

const usage = (resp && resp.usage) || {};
const latencyMs = Date.now() - Number(meta.started_ms || Date.now());

return {
  json: {
    question: meta.question,
    user_role: meta.user_role,
    model: (resp && resp.model) || meta.llm_model,
    answer,
    fontes: meta.fontes,
    retrieved_doc_ids: meta.retrieved_doc_ids,
    prompt_tokens: usage.input_tokens != null ? usage.input_tokens : 0,
    completion_tokens: usage.output_tokens != null ? usage.output_tokens : 0,
    latency_ms: latencyMs,
  },
};

// Caminho de erro da chamada ao Claude: monta uma resposta amigável e dados para auditoria.
const meta = $('Montar Prompt Ancorado').first().json;
const errMsg = ($json.error && $json.error.message) || $json.message || 'Falha ao consultar o modelo de IA.';
const latencyMs = Date.now() - Number(meta.started_ms || Date.now());
return {
  json: {
    user_role: meta.user_role,
    question: meta.question,
    model: meta.llm_model,
    answer: 'Desculpe, ocorreu um erro ao consultar o assistente de IA. Tente novamente em instantes.',
    error_message: errMsg,
    retrieved_doc_ids: meta.retrieved_doc_ids,
    fontes: meta.fontes,
    prompt_tokens: 0,
    completion_tokens: 0,
    latency_ms: latencyMs,
  },
};
